using SkiaSharp;

var imagePath = "large.png";
using var bitmapSrc = SKBitmap.Decode(imagePath);
Console.WriteLine($"Source: {bitmapSrc.Width}x{bitmapSrc.Height}");
using var bitmapDst = new SKBitmap(480, 240);
bitmapSrc.ScalePixels(bitmapDst, SKFilterQuality.High);
using var skDataWebp = bitmapDst.Encode(SKEncodedImageFormat.Webp, 75);
var outputPath = "output_v2.webp";
using (var stream = File.OpenWrite(outputPath)) skDataWebp.SaveTo(stream);
var fileInfo = new FileInfo(outputPath);
Console.WriteLine($"Output: {outputPath} - {fileInfo.Length} bytes");
Console.WriteLine("SUCCESS: test completed");

using SkiaSharp;

var imagePath = "large.png";
using var bitmapSrc = SKBitmap.Decode(imagePath);
Console.WriteLine($"Source: {bitmapSrc.Width}x{bitmapSrc.Height}");
using var bitmapDst = new SKBitmap(480, 240);
var samplingCubic = new SKSamplingOptions(SKCubicResampler.Mitchell);
bitmapSrc.ScalePixels(bitmapDst, samplingCubic);
using var dataCubic = bitmapDst.Encode(SKEncodedImageFormat.Webp, 75);
var cubicPath = "output_v3_cubic.webp";
using (var stream = File.OpenWrite(cubicPath)) dataCubic.SaveTo(stream);
var cubicSize = new FileInfo(cubicPath).Length;
Console.WriteLine($"Output (Mitchell cubic): {cubicPath} - {cubicSize} bytes");

using var bitmapDst2 = new SKBitmap(480, 240);
var samplingLinear = new SKSamplingOptions(SKFilterMode.Linear, SKMipmapMode.Linear);
bitmapSrc.ScalePixels(bitmapDst2, samplingLinear);
using var dataLinear = bitmapDst2.Encode(SKEncodedImageFormat.Webp, 75);
var linearPath = "output_v3_linear.webp";
using (var stream = File.OpenWrite(linearPath)) dataLinear.SaveTo(stream);
var linearSize = new FileInfo(linearPath).Length;
Console.WriteLine($"Output (Linear+Mipmap): {linearPath} - {linearSize} bytes");
Console.WriteLine($"Size comparison: cubic={cubicSize}, linear+mipmap={linearSize}");
Console.WriteLine("SUCCESS: test completed");
